SELECT frequency AS total_frequency
FROM lineages
WHERE lineage_name = 'lineage4';

SELECT lineage_name
FROM lineages
WHERE family = (SELECT family_id FROM families WHERE family_name = 'East-Asian');

SELECT lineage_name, frequency
FROM lineages
ORDER BY frequency DESC;

SELECT l.main_spoligotype
FROM lineages l
WHERE l.frequency = (
    SELECT MAX(frequency)
    FROM lineages
);

SELECT lineage_name
FROM lineages
WHERE frequency = (SELECT MAX(frequency) FROM lineages);

SELECT lineage_name 
FROM lineages 
WHERE parent_lineage_id IS NULL;
